__CPROVER_assigns(__CPROVER_object_whole(s->lmc->length), __CPROVER_object_whole(s->lmc->dist), __CPROVER_object_whole(s->lmc->sublen), __CPROVER_object_whole(s->lmc))
__CPROVER_frees(s->lmc->length, s->lmc->dist, s->lmc->sublen, s->lmc)

/* NOTE: Like GetBestLengths and GetCostModelMinCost, this function takes a
   function-pointer parameter (costmodel).  Under the legacy `--enforce-contract`
   flow used by the scoring harness, CBMC 6.9.0 aborts at the *cbmc* step with an
   invariant violation ("__CPROVER__start::costmodel$object was not found") in the
   "Removal of function pointers and virtual functions" pass while removing the
   function pointer from the generated `__CPROVER__start` wrapper.  The abort is
   structural -- it happens for ANY function-pointer parameter regardless of the
   contract or body -- so this function cannot be verified by the harness.
   Confirmed empirically via tools.run_cbmc: goto-cc / replace-call-with-contract /
   enforce-contract all return 0; only cbmc aborts (rc 134).  All 6 mutants are
   therefore uncheckable (the unmutated original already crashes, so every mutant
   scores identically); the kill score is 0 and unimprovable without dfcc /
   `__CPROVER_obeys_contract`, which the fixed harness does not use.

   The contract below is the strongest SOUND statement expressible: costmodel must
   be a valid (non-NULL) pointer and instart <= inend (both forwarded to and
   required by GetBestLengths), the hash handle must be non-NULL, and on the trivial
   instart == inend path GetBestLengths returns 0, TraceBackwards/FollowPath are
   empty, and the run's cost is exactly 0.  No `assigns`/`frees` clause is given:
   the function frees *path and writes length_array, costs, *store and the hash
   through its callees, so any partial frame would be an unsound (false) framing
   claim -- omitting it makes no such claim. */
static double LZ77OptimalRun(ZopfliBlockState *s,
                             const unsigned char *in, size_t instart, size_t inend,
                             unsigned short **path, size_t *pathsize,
                             unsigned short *length_array, CostModelFun *costmodel,
                             void *costcontext, ZopfliLZ77Store *store,
                             ZopfliHash *h, float *costs)
__CPROVER_requires(costmodel != NULL)
__CPROVER_requires(instart <= inend)
__CPROVER_requires(h != NULL)
__CPROVER_ensures(instart == inend ==> __CPROVER_return_value == 0)
{
    double cost = GetBestLengths(s, in, instart, inend, costmodel,
                                 costcontext, length_array, h, costs);
    free(*path);
    *path = 0;
    *pathsize = 0;
    TraceBackwards(inend - instart, length_array, path, pathsize);
    FollowPath(s, in, instart, inend, *path, *pathsize, store, h);
    assert(cost < ZOPFLI_LARGE_FLOAT);
    return cost;
}

void ZopfliCleanHash(ZopfliHash *h)
__CPROVER_requires(__CPROVER_is_fresh(h, sizeof(*h)))
__CPROVER_requires(__CPROVER_is_fresh(h->head, sizeof(*h->head)))
__CPROVER_requires(__CPROVER_is_fresh(h->prev, sizeof(*h->prev)))
__CPROVER_requires(__CPROVER_is_fresh(h->hashval, sizeof(*h->hashval)))
__CPROVER_requires(__CPROVER_is_fresh(h->head2, sizeof(*h->head2)))
__CPROVER_requires(__CPROVER_is_fresh(h->prev2, sizeof(*h->prev2)))
__CPROVER_requires(__CPROVER_is_fresh(h->hashval2, sizeof(*h->hashval2)))
__CPROVER_requires(__CPROVER_is_fresh(h->same, sizeof(*h->same)))
__CPROVER_assigns(__CPROVER_object_whole(h->head), __CPROVER_object_whole(h->prev), __CPROVER_object_whole(h->hashval), __CPROVER_object_whole(h->head2), __CPROVER_object_whole(h->prev2), __CPROVER_object_whole(h->hashval2), __CPROVER_object_whole(h->same))
__CPROVER_frees(h->head, h->prev, h->hashval, h->head2, h->prev2, h->hashval2, h->same)
__CPROVER_ensures(__CPROVER_was_freed(__CPROVER_old(h->head)))
__CPROVER_ensures(__CPROVER_was_freed(__CPROVER_old(h->prev)))
__CPROVER_ensures(__CPROVER_was_freed(__CPROVER_old(h->hashval)))
__CPROVER_ensures(__CPROVER_was_freed(__CPROVER_old(h->head2)))
__CPROVER_ensures(__CPROVER_was_freed(__CPROVER_old(h->prev2)))
__CPROVER_ensures(__CPROVER_was_freed(__CPROVER_old(h->hashval2)))
__CPROVER_ensures(__CPROVER_was_freed(__CPROVER_old(h->same)))
{
    free(h->head);
    free(h->prev);
    free(h->hashval);

    free(h->head2);
    free(h->prev2);
    free(h->hashval2);

    free(h->same);
}

void ZopfliAllocHash(size_t window_size, ZopfliHash *h)
__CPROVER_requires(window_size > 0)
__CPROVER_requires(window_size <= __CPROVER_max_malloc_size / sizeof(int))
__CPROVER_requires(__CPROVER_is_fresh(h, sizeof(*h)))
__CPROVER_assigns(__CPROVER_object_whole(h))
__CPROVER_ensures(__CPROVER_is_fresh(h->head, sizeof(int) * 65536))
__CPROVER_ensures(__CPROVER_is_fresh(h->prev, sizeof(unsigned short) * window_size))
__CPROVER_ensures(__CPROVER_is_fresh(h->hashval, sizeof(int) * window_size))
__CPROVER_ensures(__CPROVER_is_fresh(h->same, sizeof(unsigned short) * window_size))
__CPROVER_ensures(__CPROVER_is_fresh(h->head2, sizeof(int) * 65536))
__CPROVER_ensures(__CPROVER_is_fresh(h->prev2, sizeof(unsigned short) * window_size))
__CPROVER_ensures(__CPROVER_is_fresh(h->hashval2, sizeof(int) * window_size))
{
    h->head = (int *)malloc(sizeof(*h->head) * 65536);
    h->prev = (unsigned short *)malloc(sizeof(*h->prev) * window_size);
    h->hashval = (int *)malloc(sizeof(*h->hashval) * window_size);

    h->same = (unsigned short *)malloc(sizeof(*h->same) * window_size);

    h->head2 = (int *)malloc(sizeof(*h->head2) * 65536);
    h->prev2 = (unsigned short *)malloc(sizeof(*h->prev2) * window_size);
    h->hashval2 = (int *)malloc(sizeof(*h->hashval2) * window_size);
}

